    "durationSec": 4.757333333333333,
    "durationFrames": 143,
    "speaker": "ずんだもん",
    "text": "それ、心理学でpeak-end ruleって呼ばれてる現象なのだ。",
    "speakerColor": "#22c55e",
    "sceneId": 20,
    "sceneTitle": "記憶のクセ",
